const MIME = {
	png: "image/png",
	jpeg: "image/jpeg",
	webp: "image/webp"
};
function previewMime(outputFormat) {
	return MIME[outputFormat] ?? "application/octet-stream";
}
function attachPreviewResource(server) {
	let frame;
	const subscribers = /* @__PURE__ */ new Set();
	server.registerResource("live-preview", PREVIEW_URI, {
		title: "Live generation preview",
		description: "The latest frame from the most recent generate/edit call with partial_images > 0. The final frame remains available until the next streamed call starts. Subscribe to receive resources/updated as each frame arrives, then re-read to render it."
	}, () => ({ contents: frame ? [{
		uri: PREVIEW_URI,
		mimeType: frame.mimeType,
		blob: frame.blob
	}] : [] }));
	server.server.setRequestHandler(SubscribeRequestSchema, (req) => {
		subscribers.add(req.params.uri);
		return {};
	});
	server.server.setRequestHandler(UnsubscribeRequestSchema, (req) => {
		subscribers.delete(req.params.uri);
		return {};
	});
	return {
		async update(b64, mimeType) {
			frame = {
				blob: b64,
				mimeType
			};
			if (subscribers.has("imagegen://preview")) await server.server.sendResourceUpdated({ uri: PREVIEW_URI }).catch(() => {});
		},
		latest() {
			return frame;
		},
		reset() {
			frame = void 0;
		}
	};
}
//#endregion
//#region mcp-server/store.ts
function createImageStore(cap = 24) {
	const map = /* @__PURE__ */ new Map();
	let seq = 0;
	return {
		put(b64, mimeType) {
			const id = `img-${++seq}`;
			map.set(id, {
				b64,
				mimeType
			});
			if (map.size > cap) map.delete(map.keys().next().value);
			return id;
		},
		get(id) {
			return map.get(id);
		}
	};
}
