//#region mcp-server/server.ts
function buildServer(client, deployment) {
	const server = new McpServer({
		name: "imagegen",
		version: "0.1.0"
	}, { capabilities: { resources: { subscribe: true } } });
	registerImagegen(server, client, deployment);
	return server;
}
//#endregion
//#region mcp-server/index.ts
const { client, deployment } = getClient();
await buildServer(client, deployment).connect(new StdioServerTransport());
